                         <FormField name="email" control={form.control} render={({ field }: any) => (
                            <FormItem><FormLabel>Email</FormLabel><FormControl><Input {...field} type="email" /></FormControl></FormItem>
                         )} />
                         <FormField name="referredBy" control={form.control} render={({ field }: any) => (
                            <FormItem><FormLabel>Referido por</FormLabel><FormControl><Input {...field} placeholder="Ej: TikTok" /></FormControl></FormItem>
                         )} />
                      </div>
                    </AccordionContent>
                  </AccordionItem>

                  <AccordionItem value="item-2">
                    <AccordionTrigger className="font-bold text-base text-amber-600">Servicios Contratados</AccordionTrigger>
                    <AccordionContent>
                       <FormField
                          name="contractedServices"
                          control={form.control}
                          render={() => (
                            <FormItem>
                                <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-x-4 gap-y-3 rounded-md border p-4 bg-background">
                                {allServices.map((service) => (
                                  <FormField
                                    key={service.id}
                                    control={form.control}
                                    name="contractedServices"
                                    render={({ field }: any) => (
                                      <FormItem className="flex flex-row items-center space-x-2 space-y-0">
                                        <FormControl>
                                          <Checkbox
                                            checked={field.value?.includes(service.id)}
                                            onCheckedChange={(checked: boolean) => {
                                                let newValue = field.value || [];
                                                if (checked) {
                                                    newValue = [...newValue, service.id];
                                                } else {
                                                    newValue = newValue.filter((val: string) => val !== service.id);
                                                }
                                                field.onChange(newValue);
                                            }}
                                          />
                                        </FormControl>
                                        <FormLabel className="text-sm font-normal cursor-pointer">{service.name}</FormLabel>
                                      </FormItem>
                                    )}
                                  />
                                ))}
                              </div>
                            </FormItem>
                          )}
                        />
                    </AccordionContent>
                  </AccordionItem>

                  <AccordionItem value="item-3">
                    <AccordionTrigger className="font-medium">Beneficiarios</AccordionTrigger>
                    <AccordionContent>
                      {beneficiaryFields.map((field, index) => (
                        <div key={field.id} className="p-3 border rounded-md space-y-2 relative mb-2">
                            <div className="grid grid-cols-2 gap-2">
                                <FormField name={`beneficiaries.${index}.name`} control={form.control} render={({ field }: any) => (
                                    <FormItem><FormLabel>Nombre</FormLabel><FormControl><Input {...field} /></FormControl></FormItem>
                                )}/>
                                 <FormField name={`beneficiaries.${index}.documentId`} control={form.control} render={({ field }: any) => (
                                    <FormItem><FormLabel>Documento</FormLabel><FormControl><Input {...field} /></FormControl></FormItem>
                                )}/>
                            </div>
                           <Button type="button" variant="destructive" size="icon" className="absolute top-2 right-2 h-6 w-6" onClick={() => removeBeneficiary(index)}><Trash2 className="h-4 w-4"/></Button>
                        </div>
                      ))}
                      {beneficiaryFields.length < 5 && (
                        <Button type="button" variant="outline" size="sm" onClick={() => appendBeneficiary({ id: crypto.randomUUID(), name: '', documentId: '' })}>
                          <PlusCircle className="mr-2 h-4 w-4" /> Añadir Beneficiario
                        </Button>
                      )}
                    </AccordionContent>
                  </AccordionItem>

                  <AccordionItem value="item-4">
                    <AccordionTrigger className="font-medium">Costos y Comisiones</AccordionTrigger>
                    <AccordionContent>
                       <div className="p-4 bg-muted/50 rounded-lg space-y-2 mb-4">
                          <h4 className="font-semibold text-center">Resumen Financiero</h4>
                          <div className="grid grid-cols-2 md:grid-cols-4 gap-2 text-center">
                              <div><p className="text-xs text-muted-foreground">Costo Trámite</p><p className="font-bold">{totalProcedureCost.toLocaleString('es-CO', {style:'currency', currency: 'COP'})}</p></div>
                              <div>
                                <p className="text-xs text-muted-foreground">Comisión Asesor</p>
                                <p className="font-bold">{advisorCommissionValue.toLocaleString('es-CO', {style:'currency', currency: 'COP'})}</p>
                                <p className="text-[10px] text-blue-500">({commissionSummary})</p>
                              </div>
                              <div><p className="text-xs text-muted-foreground">Descuento</p><p className="font-bold">{discountValue.toLocaleString('es-CO', {style:'currency', currency: 'COP'})}</p></div>
                              <div><p className="text-xs text-muted-foreground">Valor Neto</p><p className="font-bold text-primary">{netOperationValue.toLocaleString('es-CO', {style:'currency', currency: 'COP'})}</p></div>
                          </div>
                       </div>
                    </AccordionContent>
                  </AccordionItem>

                  <AccordionItem value="item-5">
                    <AccordionTrigger className="font-bold text-base text-blue-600">Credenciales y Accesos</AccordionTrigger>
                    <AccordionContent>
                       <div className="space-y-4 pt-2">
                         {credentialFields.map((field, index) => {
                           const currentEntityId = watchedCredentials?.[index]?.entityId;
                           const linkedEntity = entities.find(e => e.id === currentEntityId);
                           const primaryLink = linkedEntity?.links?.[0]?.url;

                           return (
                           <div key={field.id} className="p-4 border rounded-xl bg-muted/20 relative space-y-3">
                              <FormField name={`credentials.${index}.entityId`} control={form.control} render={({ field: selectField }: any) => (
                                <FormItem>
                                    <FormLabel className="text-xs font-bold uppercase text-muted-foreground">Entidad / Portal</FormLabel>
                                    <Select onValueChange={(val) => {
                                        selectField.onChange(val);
                                        const selectedEntity = entities.find(e => e.id === val);
                                        if (selectedEntity) {
                                            form.setValue(`credentials.${index}.entityName`, selectedEntity.name);
                                            form.setValue(`credentials.${index}.entityType`, selectedEntity.type);
                                        }
                                    }} defaultValue={selectField.value}>
                                        <FormControl><SelectTrigger><SelectValue placeholder="Seleccionar entidad..." /></SelectTrigger></FormControl>
                                        <SelectContent>
                                            {entities.map(ent => (
                                                <SelectItem key={ent.id} value={ent.id}>{ent.name} ({ent.type})</SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>

                                    {/* Visual Link Feedback - Phase 3 Requirement */}
                                    {primaryLink && (
                                        <div className="flex items-center gap-2 mt-1.5 p-2 bg-blue-50/80 border border-blue-100 rounded-md text-xs text-blue-700 animate-in fade-in">
                                            <LinkIcon className="h-3 w-3 shrink-0" />
                                            <span className="truncate max-w-[200px] md:max-w-xs">{primaryLink}</span>
                                            <a 
                                                href={primaryLink} 
                                                target="_blank" 
                                                rel="noopener noreferrer" 
                                                className="ml-auto font-semibold hover:underline flex items-center gap-1"
                                                title="Abrir Oficina Virtual"
                                            >
                                                Ir a Portal <ExternalLink className="h-3 w-3" />
                                            </a>
                                        </div>
                                    )}

                                    <FormMessage />
                                </FormItem>
                              )} />

                              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                                  <FormField name={`credentials.${index}.username`} control={form.control} render={({ field }: any) => (
                                      <FormItem><FormLabel className="text-xs">Usuario</FormLabel><FormControl><Input {...field} /></FormControl></FormItem>
                                  )} />
                                  <FormField name={`credentials.${index}.password`} control={form.control} render={({ field }: any) => (
                                      <FormItem><FormLabel className="text-xs">Contraseña</FormLabel><FormControl><Input {...field} /></FormControl></FormItem>
                                  )} />
                              </div>

                              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                                  <FormField name={`credentials.${index}.registeredEmail`} control={form.control} render={({ field }: any) => (
                                      <FormItem><FormLabel className="text-xs">Correo Registrado</FormLabel><FormControl><Input {...field} type="email" placeholder="ejemplo@email.com" /></FormControl></FormItem>
                                  )} />
                                   <FormField name={`credentials.${index}.notes`} control={form.control} render={({ field }: any) => (
                                      <FormItem><FormLabel className="text-xs">Notas de Acceso</FormLabel><FormControl><Input {...field} placeholder="Ej: Clave temporal..." /></FormControl></FormItem>
                                  )} />
                              </div>

                              <Button type="button" variant="ghost" size="icon" className="absolute top-2 right-2 text-destructive hover:bg-destructive/10" onClick={() => removeCredential(index)}>
                                <Trash2 className="h-4 w-4"/>
                              </Button>
                           </div>
                         )})}

                         <Button type="button" variant="outline" size="sm" onClick={() => appendCredential({ id: crypto.randomUUID(), entityId: '', entityType: '', entityName: '', username: '', password: '', registeredEmail: '', notes: '' })}>
                            <KeyRound className="mr-2 h-4 w-4" /> Añadir Credencial
                         </Button>
                       </div>
                    </AccordionContent>
                  </AccordionItem>
                </Accordion>

                <div className="space-y-2">
                    <FormField name="notes" control={form.control} render={({ field }: any) => (
                        <FormItem><FormLabel>Notas Adicionales</FormLabel><FormControl><Textarea {...field} /></FormControl></FormItem>
                    )} />
                </div>
              </div>
            </ScrollArea>
            <DialogFooter className="mt-4 pt-4 border-t">
              <Button type="button" variant="ghost" onClick={() => onOpenChange(false)}>Cancelar</Button>
              <Button type="button" onClick={handleDirectSubmit}>Guardar Cliente</Button>
            </DialogFooter>
          </div>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useMemo, useCallback, type ChangeEvent } from 'react';
import { UserCog, Building, PlusCircle, Search, FileText, Edit, Trash2, Filter, Users, Clock, CheckCircle, ChevronLeft, ChevronRight, X, Download, KeyRound } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { useAppStore } from '../lib/store';
import { useClientOperations } from '../hooks/useClientOperations';
import { PageLayout } from '../components/layout/Layout';
import { Badge, Button, Input, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, Card, CardContent, Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '../components/ui/Shared';
import { EntityManagerDialog, AdvisorManagerDialog, ClientFormDialog, ClientCredentialsDialog } from '../components/features/Dialogs';
import { Client, Advisor, Entity, ClientWithMultiple } from '../lib/types';
import { serviceStatuses } from '../lib/constants';
import { useToast } from '../hooks/use-toast';
import { debounce } from '../lib/utils'; 

const ITEMS_PER_PAGE = 10;

const getStatusBadgeVariant = (status: string) => {
    switch (status.toLowerCase()) {
        case 'activo': return 'success';
        case 'en trámite': return 'info';
        case 'mora': return 'destructive';
        case 'documentación pendiente': return 'warning';
        case 'retirado': return 'gray';
        default: return 'secondary';
    }
};

export const ClientsView = () => {
  const navigate = useNavigate();
  const { toast } = useToast();

  // Store Global
  const { clients, advisors, entities, setAdvisors, setEntities } = useAppStore();

  // Hook Controlador
  const { saveClient, deleteClient } = useClientOperations();

  // Modals
  const [isClientModalOpen, setIsClientModalOpen] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [isAdvisorModalOpen, setIsAdvisorModalOpen] = useState(false);
  const [isEntityModalOpen, setIsEntityModalOpen] = useState(false);
  const [isCredentialsModalOpen, setIsCredentialsModalOpen] = useState(false);
  const [credentialsClient, setCredentialsClient] = useState<Client | null>(null);

  // Filters State
  const [searchTerm, setSearchTerm] = useState('');
  const [debouncedSearchTerm, setDebouncedSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [advisorFilter, setAdvisorFilter] = useState<string>('all');
  const [sortOrder, setSortOrder] = useState<'newest' | 'oldest' | 'name'>('newest');

  // Pagination
  const [currentPage, setCurrentPage] = useState(1);

  // Debounce search
  const handleSearchChange = useCallback((e: ChangeEvent<HTMLInputElement>) => {
      const value = e.target.value;
      setSearchTerm(value);
      const debouncedUpdate = debounce((val: string) => {
          setDebouncedSearchTerm(val);
          setCurrentPage(1);
      }, 300);
      debouncedUpdate(value);
  }, []);

  const filteredClients = useMemo(() => {
    let result = clients.filter(c => {
        const matchesSearch = !debouncedSearchTerm || 
            c.fullName.toLowerCase().includes(debouncedSearchTerm.toLowerCase()) || 
            c.documentId.includes(debouncedSearchTerm);
        const matchesStatus = statusFilter === 'all' || c.serviceStatus === statusFilter;
        const matchesAdvisor = advisorFilter === 'all' || c.assignedAdvisor === advisorFilter;
        return matchesSearch && matchesStatus && matchesAdvisor;
    });

    result.sort((a, b) => {
        if (sortOrder === 'name') return a.fullName.localeCompare(b.fullName);
        const dateA = new Date(a.entryDate).getTime();
        const dateB = new Date(b.entryDate).getTime();
        return sortOrder === 'newest' ? dateB - dateA : dateA - dateB;
    });

    return result;
  }, [clients, debouncedSearchTerm, statusFilter, advisorFilter, sortOrder]);

  const totalPages = Math.ceil(filteredClients.length / ITEMS_PER_PAGE);
  const paginatedClients = filteredClients.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  const stats = useMemo(() => ({
    total: clients.length,
    active: clients.filter(c => c.serviceStatus === 'Activo').length,
    pending: clients.filter(c => ['En trámite', 'Documentación pendiente'].includes(c.serviceStatus)).length
  }), [clients]);

  // --- Handlers ---
  const handleCreate = () => {
      setEditingClient(null);
      setIsClientModalOpen(true);
  };

  const handleEdit = (client: Client) => {
      setEditingClient(client);
      setIsClientModalOpen(true);
  };

  const handleShowCredentials = (client: Client) => {
      setCredentialsClient(client);
      setIsCredentialsModalOpen(true);
  };

  const handleSaveClientWrapper = (saveData: ClientWithMultiple) => {
    const success = saveClient(saveData);
    if (success) {
        setIsClientModalOpen(false); 
        setEditingClient(null);
    }
  };

  const handleDeleteWrapper = (clientId: string) => {
      if (window.confirm('¿Estás seguro de eliminar este cliente?\n\nEsta acción es irreversible.')) {
          deleteClient(clientId);
      }
  };

  const handleSaveAdvisors = (newAdvisors: Advisor[]) => {
      setAdvisors(newAdvisors);
      toast({ title: "Asesores actualizados", description: "La lista de asesores ha sido guardada." });
  };

  const handleSaveEntities = (newEntities: Entity[]) => {
      setEntities(newEntities);
      toast({ title: "Entidades actualizadas", description: "La lista de entidades ha sido guardada." });
  };

  const handleExportCSV = () => {
      if (filteredClients.length === 0) {
        toast({ variant: "destructive", title: "Sin datos", description: "No hay datos para exportar con los filtros actuales." });
        return;
      }
      const headers = ["ID", "Nombre", "Documento", "Tipo Doc", "Email", "Telefono", "Estado", "Asesor", "Fecha Ingreso", "Notas"];
      const csvContent = [
          headers.join(','),
          ...filteredClients.map(c => [
              c.id, `"${c.fullName}"`, c.documentId, c.documentType, c.email || '', c.phone || c.whatsapp || '', c.serviceStatus, c.assignedAdvisor || '', c.entryDate, `"${c.notes || ''}"`
          ].join(','))
      ].join('\n');
      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(blob);
      link.download = `clientes_cfbnd_${new Date().toISOString().split('T')[0]}.csv`;
      link.click();
  };

  const clearFilters = () => {
      setSearchTerm('');
      setDebouncedSearchTerm('');
      setStatusFilter('all');
      setAdvisorFilter('all');
      setCurrentPage(1);
  };

  return (
    <PageLayout 
        title="Gestión de Clientes" 
        subtitle="Administra tu base de datos y relaciones."
        onBackRoute="/app/dashboard"
        actions={
            <div className="flex flex-col sm:flex-row gap-2 w-full sm:w-auto">
                <Button variant="outline" className="w-full sm:w-auto" onClick={() => setIsAdvisorModalOpen(true)}><UserCog className="mr-2 h-4 w-4"/> Asesores</Button>
                <Button variant="outline" className="w-full sm:w-auto" onClick={() => setIsEntityModalOpen(true)}><Building className="mr-2 h-4 w-4"/> Entidades</Button>
                <Button variant="outline" className="w-full sm:w-auto" onClick={handleExportCSV} title="Descargar CSV"><Download className="mr-2 h-4 w-4"/> Exportar</Button>
                <Button className="w-full sm:w-auto shadow-lg shadow-primary/20" onClick={handleCreate}><PlusCircle className="mr-2 h-4 w-4"/> Nuevo Cliente</Button>
            </div>
        }
    >
        {/* STATS DASHBOARD */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-6">
            <Card className="bg-gradient-to-br from-blue-50 to-blue-100/50 dark:from-blue-950/40 dark:to-blue-900/10 border-blue-100 dark:border-blue-900">
                <CardContent className="p-6 flex items-center justify-between">
                    <div><p className="text-sm font-medium text-blue-600 dark:text-blue-400">Total Clientes</p><h3 className="text-3xl font-bold mt-1">{stats.total}</h3></div>
                    <div className="h-12 w-12 bg-white/50 dark:bg-blue-900/50 rounded-2xl flex items-center justify-center shadow-sm"><Users className="h-6 w-6 text-blue-600 dark:text-blue-400"/></div>
                </CardContent>
            </Card>
            <Card className="bg-gradient-to-br from-green-50 to-green-100/50 dark:from-green-950/40 dark:to-green-900/10 border-green-100 dark:border-green-900">
                <CardContent className="p-6 flex items-center justify-between">
                    <div><p className="text-sm font-medium text-green-600 dark:text-green-400">Servicios Activos</p><h3 className="text-3xl font-bold mt-1">{stats.active}</h3></div>
                    <div className="h-12 w-12 bg-white/50 dark:bg-green-900/50 rounded-2xl flex items-center justify-center shadow-sm"><CheckCircle className="h-6 w-6 text-green-600 dark:text-green-400"/></div>
                </CardContent>
            </Card>
             <Card className="bg-gradient-to-br from-amber-50 to-amber-100/50 dark:from-amber-950/40 dark:to-amber-900/10 border-amber-100 dark:border-amber-900">
                <CardContent className="p-6 flex items-center justify-between">
                    <div><p className="text-sm font-medium text-amber-600 dark:text-amber-400">En Trámite</p><h3 className="text-3xl font-bold mt-1">{stats.pending}</h3></div>
                    <div className="h-12 w-12 bg-white/50 dark:bg-amber-900/50 rounded-2xl flex items-center justify-center shadow-sm"><Clock className="h-6 w-6 text-amber-600 dark:text-amber-400"/></div>
                </CardContent>
            </Card>
        </div>

        {/* FILTER BAR */}
        <div className="bg-card p-4 rounded-xl border shadow-sm mb-6 space-y-4">
            <div className="flex flex-col md:flex-row gap-4">
                <div className="relative flex-grow">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground h-4 w-4" />
                    <Input 
                        id="search-clients"
                        name="search"
                        autoComplete="off"
                        placeholder="Buscar por nombre o documento..." 
                        className="pl-10 bg-background/50" 
                        value={searchTerm} 
                        onChange={handleSearchChange} 
                    />
                </div>
                <div className="flex flex-col sm:flex-row gap-2">
                    <Select value={statusFilter} onValueChange={(v: string) => { setStatusFilter(v); setCurrentPage(1); }}>
                        <SelectTrigger className="w-full sm:w-[180px]">
                            <div className="flex items-center gap-2">
                                <Filter className="h-4 w-4 text-muted-foreground"/>
                                <SelectValue placeholder="Estado" />
                            </div>
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="all">Todos los estados</SelectItem>
                            {serviceStatuses.map(s => <SelectItem key={s} value={s}>{s}</SelectItem>)}
                        </SelectContent>
                    </Select>

                    <Select value={advisorFilter} onValueChange={(v: string) => { setAdvisorFilter(v); setCurrentPage(1); }}>
                         <SelectTrigger className="w-full sm:w-[180px]">
                             <SelectValue placeholder="Asesor" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="all">Todos los asesores</SelectItem>
                            {advisors.map(a => <SelectItem key={a.id} value={a.name}>{a.name}</SelectItem>)}
                        </SelectContent>
                    </Select>

                    <Select value={sortOrder} onValueChange={(v: any) => setSortOrder(v)}>
                        <SelectTrigger className="w-full sm:w-[160px]">
                            <SelectValue placeholder="Orden" />
                        </SelectTrigger>
                         <SelectContent>
                            <SelectItem value="newest">Más recientes</SelectItem>
                            <SelectItem value="oldest">Más antiguos</SelectItem>
                            <SelectItem value="name">Nombre (A-Z)</SelectItem>
                        </SelectContent>
                    </Select>

                    {(searchTerm || statusFilter !== 'all' || advisorFilter !== 'all') && (
                        <Button variant="ghost" onClick={clearFilters} size="icon" title="Limpiar filtros" className="shrink-0">
                            <X className="h-4 w-4"/>
                        </Button>
                    )}
                </div>
            </div>
        </div>

        {/* DATA TABLE */}
        <Card className="overflow-hidden border shadow-sm">
            <Table>
                <TableHeader>
                    <TableRow className="bg-muted/50 hover:bg-muted/50">
                        <TableHead className="w-[300px]">Cliente</TableHead>
                        <TableHead>Documento</TableHead>
                        <TableHead>Estado</TableHead>
                        <TableHead className="hidden md:table-cell">Asesor</TableHead>
                        <TableHead className="hidden lg:table-cell">Fecha Ingreso</TableHead>
                        <TableHead className="text-right">Acciones</TableHead>
                    </TableRow>
                </TableHeader>
                <TableBody>
                    {paginatedClients.length > 0 ? (
                        paginatedClients.map(c => (
                            <TableRow key={c.id} className="group hover:bg-muted/30 transition-colors duration-200">
                                <TableCell className="font-medium">
                                    <div className="flex flex-col">
                                        <span className="text-base font-semibold group-hover:text-primary transition-colors">{c.fullName}</span>
                                        {c.phone && <span className="text-xs text-muted-foreground">{c.phone}</span>}
                                    </div>
                                </TableCell>
                                <TableCell>
                                    <Badge variant="outline" className="font-mono text-xs bg-background/50 backdrop-blur-sm">{c.documentType} {c.documentId}</Badge>
                                </TableCell>
                                <TableCell>
                                    <Badge variant={getStatusBadgeVariant(c.serviceStatus)}>{c.serviceStatus}</Badge>
                                </TableCell>
                                <TableCell className="hidden md:table-cell text-muted-foreground text-sm">{c.assignedAdvisor}</TableCell>
                                <TableCell className="hidden lg:table-cell text-muted-foreground text-sm">{c.entryDate}</TableCell>
                                <TableCell className="text-right">
                                    <div className="flex justify-end gap-1 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity">
                                        <Button variant="ghost" size="icon" className="h-8 w-8 hover:text-purple-600 hover:bg-purple-100 dark:hover:bg-purple-900/30" onClick={() => handleShowCredentials(c)} title="Ver Accesos">
                                            <KeyRound className="h-4 w-4"/>
                                        </Button>
                                        <Button variant="ghost" size="icon" className="h-8 w-8 hover:text-blue-600 hover:bg-blue-100 dark:hover:bg-blue-900/30" onClick={() => navigate('/app/documentos', { state: { clientId: c.id } })} title="Generar Documentos">
                                            <FileText className="h-4 w-4"/>
                                        </Button>
                                        <Button variant="ghost" size="icon" className="h-8 w-8 hover:text-amber-600 hover:bg-amber-100 dark:hover:bg-amber-900/30" onClick={() => handleEdit(c)} title="Editar">
                                            <Edit className="h-4 w-4"/>
                                        </Button>
                                        <Button variant="ghost" size="icon" className="h-8 w-8 hover:text-red-600 hover:bg-red-100 dark:hover:bg-red-900/30" onClick={() => handleDeleteWrapper(c.id)} title="Eliminar">
                                            <Trash2 className="h-4 w-4"/>
                                        </Button>
                                    </div>
                                </TableCell>
                            </TableRow>
                        ))
                    ) : (
                        <TableRow>
                            <TableCell colSpan={6} className="h-48 text-center">
                                <div className="flex flex-col items-center justify-center text-muted-foreground">
                                    <Search className="h-10 w-10 mb-2 opacity-20"/>
                                    <p>No se encontraron clientes con los filtros actuales.</p>
                                    <Button variant="link" onClick={clearFilters}>Limpiar filtros</Button>
                                </div>
                            </TableCell>
                        </TableRow>
                    )}
                </TableBody>
            </Table>

            {/* PAGINATION */}
            {totalPages > 1 && (
                <div className="flex flex-col sm:flex-row items-center justify-between px-4 py-4 border-t gap-4">
                    <div className="text-sm text-muted-foreground">
                        Mostrando {((currentPage - 1) * ITEMS_PER_PAGE) + 1} a {Math.min(currentPage * ITEMS_PER_PAGE, filteredClients.length)} de {filteredClients.length} clientes
                    </div>
                    <div className="flex items-center gap-2">
                        <Button variant="outline" size="sm" onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1}>
                            <ChevronLeft className="h-4 w-4 mr-1"/> Anterior
                        </Button>
                        <div className="text-sm font-medium px-2">Página {currentPage} de {totalPages}</div>
                        <Button variant="outline" size="sm" onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages}>
                            Siguiente <ChevronRight className="h-4 w-4 ml-1"/>
                        </Button>
                    </div>
                </div>
            )}
        </Card>

        <ClientFormDialog isOpen={isClientModalOpen} onOpenChange={setIsClientModalOpen} onSave={handleSaveClientWrapper} client={editingClient} advisors={advisors} />
        <AdvisorManagerDialog isOpen={isAdvisorModalOpen} onOpenChange={setIsAdvisorModalOpen} advisors={advisors} onSave={handleSaveAdvisors} />
        <EntityManagerDialog isOpen={isEntityModalOpen} onOpenChange={setIsEntityModalOpen} onSave={handleSaveEntities} allEntities={entities} />
        <ClientCredentialsDialog isOpen={isCredentialsModalOpen} onOpenChange={setIsCredentialsModalOpen} client={credentialsClient} entities={entities} />
    </PageLayout>
  );
};

